SELECT clothing_type_id, COUNT(size_preference_id) AS size_preference_count
FROM size_preferences
GROUP BY clothing_type_id;

SELECT regular_size, user_id, clothing_type_id
FROM size_preferences
WHERE size_preference_id = 0;

SELECT ct.clothing_type_name, ct.description
FROM clothing_types ct
WHERE ct.clothing_type_id IN (
    SELECT sc.clothing_type_id
    FROM size_charts sc
);
